var THREE=function(){function e(e){return e}var t={};t.WebGLRenderer=function(t){this.domElement=document.createElement("canvas");this.context=this.domElement.getContext("webgl",t);this.setSize=function(e,t){this.domElement.width=e;this.domElement.height=t;this.context.viewport(0,0,e,t)};this.render=function(){}};return t}();
</script>

<script>
(() => {
  const canvas = document.getElementById('coin-hero');
  const gl = canvas.getContext('webgl', { antialias: true });
  if (!gl) throw new Error('WebGL not supported');

  // Vertex shader
  const vsSource = `
    attribute vec3 aPosition;
    uniform mat4 uModelViewMatrix;
    uniform mat4 uProjectionMatrix;
    void main() {
      gl_Position = uProjectionMatrix * uModelViewMatrix * vec4(aPosition, 1.0);
    }
  `;

  // Fragment shader
  const fsSource = `
    precision mediump float;
    uniform vec3 uColor;
    uniform vec3 uLightDir;
    void main() {
      // Simple Lambertian + specular highlight
      float diff = max(dot(normalize(vec3(0,0,1)), -uLightDir), 0.0);
      float spec = pow(max(dot(reflect(uLightDir, normalize(vec3(0,0,1))), vec3(0,0,-1)), 0.0), 32.0);
      gl_FragColor = vec4(uColor * diff + vec3(1.0) * spec, 1.0);
    }
  `;

  // Compile shader
  function compileShader(type, source) {
    const shader = gl.createShader(type);
    gl.shaderSource(shader, source);
    gl.compileShader(shader);
    if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
      console.error(gl.getShaderInfoLog(shader));
      gl.deleteShader(shader);
      return null;
    }
    return shader;
  }

  const vertexShader = compileShader(gl.VERTEX_SHADER, vsSource);
  const fragmentShader = compileShader(gl.FRAGMENT_SHADER, fsSource);

  // Link program
  const program = gl.createProgram();
  gl.attachShader(program, vertexShader);
  gl.attachShader(program, fragmentShader);
  gl.linkProgram(program);
  if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
    console.error(gl.getProgramInfoLog(program));
  }

  // Geometry: cylinder (coin)
  const radius = 1;
  const height = 0.2;
  const segments = 64;

  const positions = [];
  const indices = [];

  for (let i = 0; i <= segments; i++) {
    const theta = (i / segments) * Math.PI * 2;
    const x = radius * Math.cos(theta);
    const y = radius * Math.sin(theta);
    // top circle
    positions.push(x, y, height / 2);
    // bottom circle
    positions.push(x, y, -height / 2);
  }

  for (let i = 0; i < segments; i++) {
    const a = i * 2;
    const b = ((i + 1) % segments) * 2;
    // side quad
    indices.push(a, a + 1, b);
    indices.push(b, a + 1, b + 1);
  }

  // Buffers
  const positionBuffer = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, positionBuffer);
  gl.bufferData(gl.ARRAY_BUFFER, new Float32Array(positions), gl.STATIC_DRAW);

  const indexBuffer = gl.createBuffer();
  gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, indexBuffer);
  gl.bufferData(gl.ELEMENT_ARRAY_BUFFER, new Uint16Array(indices), gl.STATIC_DRAW);

  // Attributes
  const aPositionLoc = gl.getAttribLocation(program, 'aPosition');
  gl.enableVertexAttribArray(aPositionLoc);
  gl.vertexAttribPointer(aPositionLoc, 3, gl.FLOAT, false, 0, 0);

  // Uniforms
  const uModelViewMatrixLoc = gl.getUniformLocation(program, 'uModelViewMatrix');
  const uProjectionMatrixLoc = gl.getUniformLocation(program, 'uProjectionMatrix');
  const uColorLoc = gl.getUniformLocation(program, 'uColor');
  const uLightDirLoc = gl.getUniformLocation(program, 'uLightDir');

  // Matrices
  function perspective(fov, aspect, near, far) {
    const f = 1.0 / Math.tan((fov * Math.PI) / 360);
    return [
      f / aspect, 0, 0, 0,
      0, f, 0, 0,
      0, 0, (far + near) / (near - far), -1,
      0, 0, (2 * far * near) / (near - far), 0
    ];
  }

  function multiply(a, b) {
    const out = new Float32Array(16);
    for (let i = 0; i < 4; ++i)
      for (let j = 0; j < 4; ++j)
        out[i * 4 + j] =
          a[0 * 4 + j] * b[i * 4 + 0] +
          a[1 * 4 + j] * b[i * 4 + 1] +
          a[2 * 4 + j] * b[i * 4 + 2] +
          a[3 * 4 + j] * b[i * 4 + 3];
    return out;
  }

  function identity() {
    const m = new Float32Array(16);
    for (let i = 0; i < 16; ++i) m[i] = i % 5 === 0 ? 1 : 0;
    return m;
  }

  function rotateY(angle) {
    const c = Math.cos(angle), s = Math.sin(angle);
    return new Float32Array([
      c, 0, -s, 0,
      0, 1, 0, 0,
      s, 0, c, 0,
      0, 0, 0, 1
    ]);
  }

  function rotateX(angle) {
    const c = Math.cos(angle), s = Math.sin(angle);
    return new Float32Array([
      1, 0, 0, 0,
      0, c, -s, 0,
      0, s, c, 0,
      0, 0, 0, 1
    ]);
  }

  // Render function
  let lastTime = 0;
  let animRequest = null;

  function render(t) {
    gl.viewport(0, 0, canvas.width, canvas.height);
    gl.clearColor(0.95, 0.95, 0.95, 1);
    gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
    gl.enable(gl.DEPTH_TEST);

    const aspect = canvas.width / canvas.height;
    const proj = perspective(45, aspect, 0.1, 10);
    let mv = identity();
    mv = multiply(mv, rotateY(t * Math.PI * 2));
    mv = multiply(mv, rotateX(t * Math.PI));

    gl.useProgram(program);
    gl.uniformMatrix4fv(uModelViewMatrixLoc, false, mv);
    gl.uniformMatrix4fv(uProjectionMatrixLoc, false, proj);
    gl.uniform3f(uColorLoc, 0.8, 0.8, 0.8); // base metallic color
    gl.uniform3f(uLightDirLoc, Math.sin(t * Math.PI), 0.5, Math.cos(t * Math.PI));

    gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, indexBuffer);
    gl.drawElements(gl.TRIANGLES, indices.length, gl.UNSIGNED_SHORT, 0);
  }

  function loop(now) {
    const t = ((now - lastTime) % 4000) / 4000; // 4s cycle
    render(t);
    animRequest = requestAnimationFrame(loop);
  }

  // Start animation
  animRequest = requestAnimationFrame(loop);

  // Expose API
  window.demo = {
    canvas,
    setTime: (t) => { render(Math.max(0, Math.min(1, t))); },
    pause: () => { if (animRequest) cancelAnimationFrame(animRequest); }
  };
})();
</script>
</body>
</html>
